using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class ExampleTests
{
    private readonly TestContext _testContext;
    private readonly MyService _service;

    // Constructor: sync init + TestContext injection (MSTest 3.6+)
    public ExampleTests(TestContext testContext)
    {
        _testContext = testContext;
        _service = new MyService();
    }

    // TestInitialize: ONLY for async setup
    [TestInitialize]
    public async Task InitAsync()
    {
        await _service.ConnectAsync(_testContext.CancellationToken);
    }

    [TestCleanup]
    public async Task CleanupAsync()
    {
        await _service.DisconnectAsync();
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task GetData_ReturnsExpectedResult()
    {
        var result = await _service.GetDataAsync(_testContext.CancellationToken);

        Assert.IsNotNull(result);
    }
}

// Stub for demonstration
public class MyService
{
    public Task ConnectAsync(CancellationToken ct = default) => Task.CompletedTask;
    public Task DisconnectAsync() => Task.CompletedTask;
    public Task<string> GetDataAsync(CancellationToken ct = default) => Task.FromResult("data");
}

